diff --git a/tests/core/examples.test.js b/tests/core/examples.test.js
new file mode 100644
index 0000000..88e5a96
--- /dev/null
+++ b/tests/core/examples.test.js
@@ -0,0 +1,47 @@
+/* eslint-env jest */
+
+import React, { Component } from 'react';
+import { shallow } from 'enzyme';
+import { shallowToJson } from '../../src';
+
+class MyComponent extends Component {
+    constructor() {
+        super();
+        this.handleClick = this.handleClick.bind(this);
+        this.state = { count: 1 };
+    }
+
+    handleClick() {
+        this.setState(({ count }) => ({ count: count + 1 }));
+    }
+
+    render() {
+        return (
+            <div className={this.props.className} onClick={this.handleClick}>
+                <span className="count">{this.state.count}</span>
+                {this.props.children}
+            </div>
+        );
+    }
+}
+
+it('renders correctly', () => {
+    const wrapper = shallow(
+        <MyComponent className="my-component">
+            <strong>Hello World!</strong>
+        </MyComponent>
+    );
+
+    expect(shallowToJson(wrapper)).toMatchSnapshot();
+});
+
+it('renders span after setState', () => {
+    const wrapper = shallow(
+        <MyComponent className="my-component">
+            <strong>Hello World!</strong>
+        </MyComponent>
+    );
+
+    wrapper.setState({ count: 42 });
+    expect(shallowToJson(wrapper.find('span'))).toMatchSnapshot();
+});

diff --git a/tests/core/focused.test.js b/tests/core/focused.test.js
new file mode 100644
index 0000000..ed4989f
--- /dev/null
+++ b/tests/core/focused.test.js
@@ -0,0 +1,40 @@
+/* eslint-env jest */
+
+import React from 'react';
+import { shallow } from 'enzyme';
+import { shallowToJson } from '../../src';
+
+const MyComponent = props => (
+    <div className={`my-component ${props.className}`}>
+        <h3>Component Title</h3>
+        <span>{props.children}</span>
+    </div>
+);
+
+it('renders the right title', () => {
+    const wrapper = shallow(
+        <MyComponent className="strong-class"/>
+    );
+
+    expect(shallowToJson(wrapper.find('h3'))).toMatchSnapshot();
+});
+
+it('renders a `strong` correctly', () => {
+    const wrapper = shallow(
+        <MyComponent className="strong-class">
+            <strong>Hello World!</strong>
+        </MyComponent>
+    );
+
+    expect(shallowToJson(wrapper.find('span').first())).toMatchSnapshot();
+});
+
+it('renders a `span` correctly', () => {
+    const wrapper = shallow(
+        <MyComponent className="span-class">
+            <span>Hello World!</span>
+        </MyComponent>
+    );
+
+    expect(shallowToJson(wrapper.find('span').first())).toMatchSnapshot();
+});

diff --git a/tests/core/mount.test.js b/tests/core/mount.test.js
new file mode 100644
index 0000000..5992269
--- /dev/null
+++ b/tests/core/mount.test.js
@@ -0,0 +1,55 @@
+/* eslint-env jest */
+
+import React from 'react';
+import { mount } from 'enzyme';
+import { mountToJson } from '../../src';
+import { BasicPure, BasicWithUndefined } from './fixtures/pure-function';
+import { BasicClass, ClassWithPure, ClassWithDirectPure, ClassWithDirectComponent } from './fixtures/class';
+
+it('converts basic pure mount', () => {
+    const mounted = mount(
+        <BasicPure className="pure"><strong>Hello!</strong></BasicPure>
+    );
+
+    expect(mountToJson(mounted)).toMatchSnapshot();
+});
+
+it('converts basic class mount', () => {
+    const mounted = mount(
+        <BasicClass className="class"><strong>Hello!</strong></BasicClass>
+    );
+
+    expect(mountToJson(mounted)).toMatchSnapshot();
+});
+
+it('converts a class mount with a pure function in it', () => {
+    const mounted = mount(
+        <ClassWithPure className="class"><strong>Hello!</strong></ClassWithPure>
+    );
+
+    expect(mountToJson(mounted)).toMatchSnapshot();
+});
+
+it('converts a class mount with a pure function in it as a direct child', () => {
+    const mounted = mount(
+        <ClassWithDirectPure className="class"><strong>Hello!</strong></ClassWithDirectPure>
+    );
+
+    expect(mountToJson(mounted)).toMatchSnapshot();
+});
+
+it('converts a class mount with a class component in it as a direct child', () => {
+    const mounted = mount(
+        <ClassWithDirectComponent className="class"><strong>Hello!</strong></ClassWithDirectComponent>
+    );
+
+    expect(mountToJson(mounted)).toMatchSnapshot();
+});
+
+it('skips undefined props', () => {
+    const mounted = mount(
+        <BasicWithUndefined>Hello!</BasicWithUndefined>
+    );
+
+    expect(mountToJson(mounted)).toMatchSnapshot();
+});

